}.amag_n_verde a{
    display: block;
    width: 133px;
    height: 83px;
    line-height: 83px;
    /*background: url(https://sogeriacqua.it/wp-content/uploads/2019/03/numero-verde.png) center no-repeat;*/
    background: url(https://sogeriacqua.it/wp-content/uploads/2019/04/numero-verde-100.jpg) center no-repeat;
    text-indent: -9999px;
}

.single-amm-trasparente .fusion-page-title-bar .fusion-page-title-secondary, .single-amm-trasparente .fusion-meta-info{
    display:none;
}

.single-amm-trasparente .fusion-page-title-bar h1.entry-title{
    font-size:30px;
}

li.sistema-di-misurazione-e-valutazione-della-performance, li.documento-delloiv-di-validazione-della-relazione-sulla-performance {
    display: none;
}

.tax-tipologie .fusion-blog-layout-grid .fusion-post-grid {
    width: 100% !important;
    display: block !important;
    top: 0 !important;
    left: 0 !important;
    float: none;
    position: relative !important;
    padding: 0!important;
    padding-bottom: 0!important;
    margin-bottom: 20px;
    border-bottom: 1px solid #eaeaea;
}

.tax-tipologie .fusion-blog-layout-grid .fusion-post-grid .fusion-single-line-meta, .tax-tipologie .fusion-blog-layout-grid .fusion-post-grid .fusion-content-sep,  .tax-tipologie .fusion-blog-layout-grid .fusion-post-grid .fusion-meta-info{
    display:none;
}

.tax-tipologie .fusion-blog-layout-grid .fusion-post-grid .fusion-post-content-wrapper{
    padding:0;
}

.tax-tipologie .fusion-blog-layout-grid .fusion-post-grid .fusion-post-wrapper{
    border:0;
}

.tax-tipologie .fusion-blog-layout-grid .fusion-post-grid a{
    color:#000000!important;
}

.tax-tipologie .fusion-blog-layout-grid .fusion-post-grid a:hover{
    color:#00b7d8!important;
}

/*.widget_atwidget{
    display:none;
}*/

.fusion-sharing-box{
    display:none;
}

.term-bandi-di-gara-e-contratti #posts-container{
    margin-top:50px;
}

.tax-tipologie .widget_recent_entries{
    display:none;
}

.counters-box .content-box-percentage {
    color: #7dbedc;
}

.gruppoamag_scadenza{
    display:block!important;
}

@media only screen and (max-width: 800px){
    .amag_n_verde a{
        margin:10px 0;
    }
