document.addeventlistener("domcontentloaded", () => {
    // cerchiamo i tag che potrebbero contenere la scritta
    const selectors = ['div', 'span', 'a', 'p', 'h1', 'h2'];

    selectors.foreach(selector => {
        const elements = document.queryselectorall(selector);
        elements.foreach(el => {
            // se l'elemento contiene esattamente quella dicitura
            if (el.textcontent.trim() === "regione lombardia") {
                // rendiamo il testo trasparente così la fascia rossa resta visibile
                el.style.setproperty('color', 'transparent', 'important');
            }
        });
    });
});
